class Solution:
    def distinctSequences(self, n: int) -> int:
        if n == 1:
            return 6
        MOD = 10**9 + 7

        # Precompute coprime pairs
        coprime = [[False]*7 for _ in range(7)]
        for a in range(1, 7):
            for b in range(1, 7):
                if a != b and gcd(a, b) == 1:
                    coprime[a][b] = True

        # dp[i][a][b] = number of sequences of length i ending with (a, b)
        # Initialize for i=2
        dp = [[[0]*7 for _ in range(7)] for __ in range(n+1)]
        for a in range(1, 7):
            for b in range(1, 7):
                if a != b and coprime[a][b]:
                    dp[2][a][b] = 1

        for i in range(3, n+1):
            new_dp = [[0]*7 for _ in range(7)]
            for a in range(1, 7):
                for b in range(1, 7):
                    if dp[i-1][a][b] == 0:
                        continue
                    for c in range(1, 7):
                        if c != a and c != b and coprime[b][c]:
                            new_dp[b][c] = (new_dp[b][c] + dp[i-1][a][b]) % MOD
            dp[i] = new_dp

        total = 0
        for a in range(1, 7):
            for b in range(1, 7):
                total = (total + dp[n][a][b]) % MOD
        return total

